const item = $('처리 대상 선택').first().json;

const reference = item.reference || '';
const passage = item.passage || '';
const sTitle = item.sermon_title || '';

let outline = '';
let summaryInput = '';
let transcript = '';
let legacyPoints = '';

try {
  const parsedPoints = item.sermon_points ? JSON.parse(item.sermon_points) : null;
  if (parsedPoints && typeof parsedPoints === 'object') {
    outline = parsedPoints.outline || '';
    summaryInput = parsedPoints.summary || '';
    transcript = parsedPoints.transcript || '';
    legacyPoints = parsedPoints.legacy_points || '';
  } else if (item.sermon_points) {
    legacyPoints = item.sermon_points;
  }
} catch (e) {
  legacyPoints = item.sermon_points || '';
}

const lines = [
  '너는 개혁주의 신학(성경의 충분성, 하나님의 주권, 인간의 죄성, 은혜 중심 구원, 그리스도 중심 해석)에 충실한 청년부 소그룹 질문 설계자다.',
  '반드시 입력 본문/설교자료에 근거하여 작성하고, 추측 확장은 금지한다.',
  '',
  '[목표]',
  '- 질문 수를 최소화하고 단락별로 깊이 집중한다.',
  '- 질문 의도 설명(explanation) 없이, 질문 문장 자체에 맥락이 자연스럽게 드러나게 작성한다.',
  '- 정죄형이 아니라 회개/믿음/순종/공동체 실천으로 이어지게 한다.',
  '',
  '[질문 생성 규칙]',
  '- 최대 4개 섹션만 선택한다(핵심 단락 위주).',
  '- 섹션당 질문은 1~2개만 생성한다.',
  '- 전체 질문 수는 6개를 넘기지 않는다.',
  '- 각 질문은 1문장, 길이 120자 내외.',
  '- 질문 category는 observation|interpretation|gospel|application|community 중 하나.',
  '',
  '성경 구절: ' + reference,
  sTitle ? ('설교 제목: ' + sTitle) : '',
  outline ? ('설교 대지:\n' + outline) : '',
  summaryInput ? ('설교 요약:\n' + summaryInput) : '',
  transcript ? ('설교 원문:\n' + transcript) : '',
  legacyPoints ? ('추가 메모:\n' + legacyPoints) : '',
  '성경 본문(개역개정):',
  passage,
  '',
  '[반환 형식: JSON만, 코드블록 금지]',
  '{',
  '  "sermon_summary": {',
  '    "key_point": "핵심 메시지 1문장",',
  '    "overview": "전체 흐름 2~3문장",',
  '    "sections": [',
  '      { "title": "단락 제목", "content": "단락 요약 1~2문장" }',
  '    ]',
  '  },',
  '  "questions": {',
  '    "sections": [',
  '      {',
  '        "section_title": "단락/대지",',
  '        "summary_anchor": "이 단락 핵심 1문장",',
  '        "questions": [',
  '          {',
  '            "category": "observation|interpretation|gospel|application|community",',
  '            "question": "맥락이 내재된 실제 나눔 질문 1문장",',
  '            "scripture_anchor": "관련 구절"',
  '          }',
  '        ]',
  '      }',
  '    ]',
  '  }',
  '}',
  '',
  '응답이 길어질 경우 섹션/질문 수를 줄여서라도 반드시 완전한 JSON 객체를 닫아서 반환하라.'
];

return [{
  json: {
    id: item.id,
    userMsg: lines.filter(Boolean).join('\n')
  }
}];

const input = $input.first().json;

function pickRaw(i) {
  if (i.content?.[0]?.text) return i.content[0].text;
  if (i.text) return i.text;
  if (i.output) return i.output;
  if (i.message) return i.message;
  return JSON.stringify(i);
}

function extractJsonText(raw) {
  let t = String(raw || '').trim();
  t = t.replace(/^\`\`\`json\s*/i, '').replace(/^\`\`\`\s*/i, '').replace(/\`\`\`\s*$/i, '').trim();
  const first = t.indexOf('{');
  const last = t.lastIndexOf('}');
  if (first !== -1 && last !== -1 && last > first) t = t.slice(first, last + 1);
  return t;
}

function repairJson(text) {
  let t = text;
  t = t.replace(/[“”]/g, '"').replace(/[‘’]/g, "'");
  t = t.replace(/,\s*([}\]])/g, '$1');
  t = t.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F]/g, '');
  return t;
}

const raw = pickRaw(input);
const candidate = extractJsonText(raw);
if (!candidate || candidate.indexOf('{') === -1 || candidate.lastIndexOf('}') === -1) {
  throw new Error('truncated response: JSON 객체 경계를 찾지 못했습니다');
}

let parsed;
try {
  parsed = JSON.parse(candidate);
} catch (e1) {
  try {
    parsed = JSON.parse(repairJson(candidate));
  } catch (e2) {
    throw new Error('JSON 파싱 실패: ' + e2.message + '\n---원본 일부---\n' + String(raw).slice(0, 700));
  }
}

const qRoot = parsed.questions || {};
const sections = Array.isArray(qRoot.sections) ? qRoot.sections : [];

const normalizedSections = sections
  .map((sec, secIdx) => {
    const title = sec?.section_title || sec?.title || sec?.topic || ('섹션 ' + (secIdx + 1));
    const anchor = sec?.summary_anchor || sec?.summary || '';
    const qList = Array.isArray(sec?.questions) ? sec.questions : [];

    const normalizedQuestions = qList
      .map((q) => {
        if (typeof q === 'string') {
          return { section_title: title, category: 'application', question: q, scripture_anchor: '' };
        }
        return {
          section_title: title,
          category: q?.category || q?.type || 'application',
          question: q?.question || q?.text || q?.content || '',
          scripture_anchor: q?.scripture_anchor || q?.anchor || ''
        };
      })
      .filter((q) => q.question);

    return { section_title: title, summary_anchor: anchor, questions: normalizedQuestions };
  })
  .filter((sec) => sec.questions.length > 0)
  .slice(0, 4);

let count = 0;
const limitedSections = normalizedSections.map((sec) => {
  const next = [];
  for (const q of sec.questions) {
    if (count >= 6) break;
    next.push(q);
    count += 1;
  }
  return { ...sec, questions: next };
}).filter((sec) => sec.questions.length > 0);

if (!limitedSections.length) {
  throw new Error('유효한 sections/questions가 없습니다. 받은 키: ' + Object.keys(parsed).join(', '));
}

const flattened = limitedSections.flatMap((sec) => sec.questions);

const summaryRaw = parsed.sermon_summary || {};
const sermon_summary = {
  key_point: summaryRaw?.key_point || '',
  overview: summaryRaw?.overview || '',
  sections: Array.isArray(summaryRaw?.sections)
    ? summaryRaw.sections.map((s) => ({ title: s?.title || '', content: s?.content || '' })).filter((s) => s.title || s.content)
    : []
};

const id = $('처리 대상 선택').first().json.id;

return [{
  json: {
    id,
    questions: {
      sections: limitedSections,
      flat: flattened,
      meta: qRoot?.meta || {}
    },
    sermon_summary
  }
}];

const rows = $input.all().map(i => i.json || {});
const now = Date.now();
const STALE_MIN = 10;
const staleMs = STALE_MIN * 60 * 1000;

const isPending = (r) => r?.status === 'pending';
const isStaleProcessing = (r) => {
  if (r?.status !== 'processing') return false;
  const t = r?.updated_at || r?.created_at;
  if (!t) return true;
  const ts = new Date(t).getTime();
  if (Number.isNaN(ts)) return true;
  return (now - ts) >= staleMs;
};

const pending = rows
  .filter(isPending)
  .sort((a,b)=> new Date(a.created_at||0)-new Date(b.created_at||0));

const staleProcessing = rows
  .filter(isStaleProcessing)
  .sort((a,b)=> new Date(a.updated_at||a.created_at||0)-new Date(b.updated_at||b.created_at||0));

const target = pending[0] || staleProcessing[0];

if (!target) return [];

return [{ json: target }];
